-- Patchnote 0.8.5 seed + condense every existing patchnote (shorter titles & descriptions).
-- The UPDATEs are deterministic (safe to re-run); the 0.8.5 INSERT is ON CONFLICT DO NOTHING.
-- Content trimmed to a concise style; entry count, order and `type` preserved per version.

UPDATE "Patchnote" SET "titleEn"='Opt-in *arr user tagging, no more hardcoded `ndp-`', "titleFr"='Tagging utilisateur *arr opt-in, fini le préfixe `ndp-`', "entries"='[{"type":"feat","titleEn":"Per-user *arr tagging is now an opt-in setting","titleFr":"Le tagging utilisateur *arr devient opt-in","descEn":"A toggle under Admin → Configuration now controls the `ndp-<username>` tagging Oscarr sent to Radarr/Sonarr. When on, the prefix becomes `oscarr-`. Off by default.","descFr":"Un toggle sous Admin → Configuration contrôle désormais le tag `ndp-<username>` qu''Oscarr envoyait à Radarr/Sonarr. Activé, le préfixe devient `oscarr-`. Désactivé par défaut."},{"type":"note","titleEn":"Existing `ndp-*` tags in your *arr are NOT migrated","titleFr":"Les anciens tags `ndp-*` *arr ne sont PAS migrés","descEn":"Oscarr never touches tags from past versions. After upgrading from pre-0.8.4, old `ndp-<username>` tags stay as harmless orphans — delete them in the *arr UI (Settings → Tags).","descFr":"Oscarr ne touche pas aux tags des versions précédentes. Après un upgrade pré-0.8.4, les tags `ndp-<username>` restent orphelins — supprime-les dans l''UI *arr (Settings → Tags)."}]' WHERE "version"='0.8.4';
UPDATE "Patchnote" SET "titleEn"='Fix plugin compat — Discover flags incompat, prod version OK', "titleFr"='Compat plugins — incompat dans Discover, version prod OK', "entries"='[{"type":"fix","titleEn":"Backend reports the right Oscarr version in prod","titleFr":"Le backend reporte la bonne version d''Oscarr en prod","descEn":"The prod Docker image read its version from `package.prod.json`, stuck at 0.7.2 — so plugins needing Oscarr >=0.8.x were silently refused. Compat now reads the root `package.json`.","descFr":"L''image Docker prod lisait sa version depuis `package.prod.json`, resté à 0.7.2 — donc les plugins exigeant Oscarr >=0.8.x étaient refusés. La compat lit le `package.json` root."},{"type":"fix","titleEn":"Discover catalog surfaces plugin engine compatibility","titleFr":"Discover signale la compatibilité moteur des plugins","descEn":"The Discover catalog now flags each plugin''s compat with your Oscarr version. Incompatible ones show a disabled Install button labelled ''Requires Oscarr <range>''.","descFr":"Le catalogue Discover signale désormais la compat de chaque plugin avec ta version d''Oscarr. Les incompatibles ont un bouton Install désactivé, libellé ''Requires Oscarr <range>''."},{"type":"fix","titleEn":"Reload button now force-refreshes the Discover catalog","titleFr":"Le bouton Recharger rafraîchit le catalogue Discover","descEn":"Reload only busted the update-check cache, so the Discover catalog stayed on its 30-min cache. It now also force-refreshes the registry, so new or updated plugins surface at once.","descFr":"Recharger ne vidait que le cache d''updates ; le catalogue Discover restait sur son cache de 30 min. Il rafraîchit désormais le registre : plugins neufs ou à jour visibles vite."}]' WHERE "version"='0.8.3';
UPDATE "Patchnote" SET "titleEn"='Install wizard 2.0, Seerr-family migration, plugin SDK i18n', "titleFr"='Assistant 2.0, migration Seerr-famille, i18n SDK plugin', "entries"='[{"type":"feat","titleEn":"Install wizard 2.0 — guided setup, checklist exit","titleFr":"Install 2.0 — parcours guidé, sortie sur checklist","descEn":"Rewritten end-to-end as a guided 7-step flow with a vertical stepper. It seeds quality tiers, auto-maps *arr profiles, and ends on the setup-checklist — no half-wired installs.","descFr":"Réécrit de bout en bout : parcours guidé en 7 étapes, stepper vertical. Seed les paliers, auto-mappe les profils *arr, et finit sur la setup-checklist — fini les installs bâclées."},{"type":"feat","titleEn":"Migrate from Overseerr / Jellyseerr / Seerr at install","titleFr":"Migration Overseerr / Jellyseerr / Seerr à l''install","descEn":"A Fresh / Migrate picker probes a Seerr source and bootstraps services, root folders and quality tiers. *arr keys and the Plex token aren''t exported — re-add them in Services.","descFr":"Un sélecteur Fresh / Migration sonde une source Seerr et bootstrap services, dossiers racine et paliers. Clés *arr et token Plex non exportés — re-saisis-les dans Services."},{"type":"feat","titleEn":"Import users and requests from Seerr apps (admin tab)","titleFr":"Import utilisateurs et demandes Seerr (onglet admin)","descEn":"A dedicated Import tab pulls users and request history from any Seerr server, no wizard needed. Preview and map users (link/create/skip). Status 4 maps to approved, not pending.","descFr":"Un onglet Import dédié récupère users et demandes depuis tout serveur Seerr, hors assistant. Aperçu + mapping (lier/créer/ignorer). Statut 4 en approved, plus pending."},{"type":"feat","titleEn":"Quality auto-mapping endpoint","titleFr":"Endpoint d''auto-mapping qualité","descEn":"POST /admin/quality-mappings/auto scans your Radarr/Sonarr profiles and maps them to Oscarr tiers by name (4K HDR / 4K / HD / SD). Idempotent; run by the wizard or the Quality tab.","descFr":"POST /admin/quality-mappings/auto scanne tes profils Radarr/Sonarr et les mappe aux paliers Oscarr par nom (4K HDR / 4K / HD / SD). Idempotent ; via l''assistant ou l''onglet Qualité."},{"type":"feat","titleEn":"Plugin SDK gains language + translation helpers","titleFr":"Le SDK plugin gagne des helpers langue et traduction","descEn":"@oscarr/sdk now exposes getLang(), a useLanguage() hook and t() with fallback + interpolation. Plugins ship their own per-locale dicts and hot-switch — no react-i18next needed.","descFr":"@oscarr/sdk expose getLang(), un hook useLanguage() et t() avec fallback + interpolation. Les plugins embarquent leurs dicos par locale et hot-switch — pas de react-i18next."},{"type":"feat","titleEn":"Plugin guard handlers receive request context","titleFr":"Les guards plugin reçoivent le contexte de la requête","descEn":"registerGuards() handlers now get tmdbId, mediaType and seasons with the user, so plugins like Quotas can gate on what''s requested, not just who. Fields are additive.","descFr":"Les handlers registerGuards() reçoivent tmdbId, mediaType et seasons avec l''utilisateur — les plugins comme Quotas peuvent gater sur la demande, pas juste qui. Champs additifs."},{"type":"feat","titleEn":"Surface undecryptable service credentials in admin UI","titleFr":"Identifiants non déchiffrables signalés en admin","descEn":"After restoring a backup from another instance (different OSCARR_SECRET_KEY), credentials can''t be decrypted. Affected rows show a warning and blank password fields to re-enter.","descFr":"Après un backup restauré d''une autre instance (OSCARR_SECRET_KEY différente), les identifiants ne se déchiffrent plus. Lignes touchées : alerte + champs password vides à re-saisir."},{"type":"fix","titleEn":"Backend no longer restarts after install","titleFr":"Le backend ne redémarre plus après l''install","descEn":"/setup/sync used to process.exit(0) after finishing, relying on a supervisor to respawn. Without one the app stayed dark. The exit is gone — it now runs in-process.","descFr":"/setup/sync appelait process.exit(0) après l''install, comptant sur un superviseur pour respawn. Sans lui l''app restait dark. L''exit est retiré — elle tourne in-process."},{"type":"fix","titleEn":"Plugin toggle refuses incompatible / failed plugins","titleFr":"Le toggle refuse les plugins incompatibles / en échec","descEn":"Toggling on a plugin that failed to load used to throw a Prisma RecordNotFound. togglePlugin now bails early with the reason; the UI disables the switch, reason in tooltip.","descFr":"Activer un plugin qui n''a pas chargé levait un Prisma RecordNotFound cryptique. togglePlugin sort tôt avec la vraie raison ; l''UI désactive le toggle, raison dans le tooltip."},{"type":"fix","titleEn":"docker-compose now injects OSCARR_SECRET_KEY","titleFr":"docker-compose injecte OSCARR_SECRET_KEY au conteneur","descEn":"compose interpolates .env for YAML, not container env. The docker-compose.yml now adds env_file + an explicit OSCARR_SECRET_KEY, so 0.8.1''s secret check passes on upgrades.","descFr":"compose n''interpole .env que pour le YAML, pas l''env conteneur. Le docker-compose.yml ajoute env_file + un OSCARR_SECRET_KEY explicite, pour que le check secret de 0.8.1 passe."}]' WHERE "version"='0.8.2';
UPDATE "Patchnote" SET "titleEn"='Seerr-compatible API, encryption-at-rest, qBittorrent 5.x', "titleFr"='API compatible Seerr, chiffrement au repos, qBittorrent 5.x', "entries"='[{"type":"feat","titleEn":"Seerr-compatible API layer at /api/v1/*","titleFr":"Couche API compatible Seerr sous /api/v1/*","descEn":"Third-party tools that speak Overseerr/Jellyseerr/Seerr point to Oscarr, no native integration needed. Tested with Homarr and Doplarr. Unimplemented endpoints return a clean 501.","descFr":"Les outils qui parlent Overseerr/Jellyseerr/Seerr pointent sur Oscarr sans intégration native. Testé avec Homarr et Doplarr. Compat best-effort, endpoints non implémentés → 501."},{"type":"feat","titleEn":"Per-app API keys with revocation","titleFr":"Clés API par application avec révocation","descEn":"One named key per integration (Admin → Access → API Keys). sha256-hashed at rest, one-click soft-delete keeps the audit trail. The global key stays for `/webhooks` and `/health`.","descFr":"Une clé nommée par intégration (Admin → Access → API Keys). Hashées en sha256, révocation en un clic avec historique. La clé globale reste pour `/webhooks` et `/health`."},{"type":"feat","titleEn":"AES-256-GCM encryption at rest for service credentials","titleFr":"Chiffrement AES-256-GCM des identifiants de service","descEn":"Credentials in `Service.config` are now encrypted at rest with AES-256-GCM via the new mandatory `OSCARR_SECRET_KEY` env var. Re-save each service to migrate existing plaintext.","descFr":"Les identifiants dans `Service.config` sont chiffrés en AES-256-GCM via la nouvelle variable obligatoire `OSCARR_SECRET_KEY`. Re-sauvegarde tes services pour migrer l''existant."},{"type":"feat","titleEn":"Secure reveal/copy for stored credentials","titleFr":"Affichage et copie sécurisés des identifiants stockés","descEn":"Replaces `globalThis.prompt()` with an accessible in-app modal. Reveal shows the value for 8 s then auto-remasks; copy fetches it server-side and never shows it on screen.","descFr":"Remplace `globalThis.prompt()` par un modal accessible. La révélation affiche la valeur 8 s puis re-masque ; la copie passe par le serveur, sans jamais l''afficher."},{"type":"feat","titleEn":"qBittorrent 5.x compatibility (API key auth)","titleFr":"Compatibilité qBittorrent 5.x (auth par clé API)","descEn":"qBit 5.x renamed the session cookie and the pause/resume endpoints. Connector now uses 5.x API key auth (qBit Settings → WebUI → Authentication). Manager plugin follows in v0.2.0.","descFr":"qBit 5.x a renommé cookie de session et endpoints pause/resume. Le connecteur passe à l''auth par clé API (qBit Settings → WebUI → Authentication). Plugin Manager suit en v0.2.0."},{"type":"feat","titleEn":"TMDB trending backdrop on the login page","titleFr":"Backdrop TMDB en tendance sur la page de login","descEn":"The login page picks a random backdrop from the top 10 trending titles and locks it until the next hard refresh. Reuses `/api/tmdb/trending`, now public.","descFr":"La page de login tire un backdrop au hasard parmi les 10 titres tendance et le fige jusqu''au prochain rafraîchissement. Réutilise `/api/tmdb/trending`, désormais public."},{"type":"feat","titleEn":"Searchable Discover + reusable ConfirmModal","titleFr":"Recherche/filtres Discover + ConfirmModal réutilisable","descEn":"The Plugins → Discover tab gains search, a Hide installed toggle (on by default) and a New filter (< 14 days). Destructive admin actions now use a reusable ConfirmModal.","descFr":"L''onglet Plugins → Discover gagne recherche, toggle Masquer les installés (activé par défaut) et filtre Nouveau (< 14 jours). Les actions destructives passent à un ConfirmModal."},{"type":"refactor","titleEn":"Drop *arr tag-based request sync","titleFr":"Suppression du sync des demandes basé sur les tags *arr","descEn":"The cron that walked Radarr/Sonarr tags every 5 min is gone: brittle precondition, mis-attributed requests. The legacy `CronJob` row drops via migration. Import tracked under #192.","descFr":"Le cron qui parcourait les tags Radarr/Sonarr toutes les 5 min est supprimé : précondition fragile, attributions erronées. La `CronJob` part en migration. Import tracké sous #192."},{"type":"fix","titleEn":"Bump better-sqlite3 to 12.9 for Node 24+ support","titleFr":"Bump better-sqlite3 vers 12.9 pour le support Node 24+","descEn":"better-sqlite3 11.10 only shipped prebuilt binaries up to Node 22 and failed to build on Node 24+. 12.9 covers 20.x → 25.x and clears the `NODE_MODULE_VERSION` mismatch.","descFr":"better-sqlite3 11.10 ne fournissait des binaires que jusqu''à Node 22 et cassait en Node 24+. La 12.9 couvre 20.x → 25.x et résout le mismatch `NODE_MODULE_VERSION`."},{"type":"other","titleEn":"Slim README + docs/installation.md","titleFr":"README allégé + docs/installation.md","descEn":"The README drops from 280 lines to the pitch + Docker quick-start. Bare-metal install, the full env-var reference and the project tree move to `docs/installation.md`.","descFr":"Le README passe de 280 lignes au pitch + quick-start Docker. L''install bare-metal, la référence des variables d''env et la structure du projet vont dans `docs/installation.md`."}]' WHERE "version"='0.8.1';
UPDATE "Patchnote" SET "titleEn"='Plugin self-update, generic storage, connector pack', "titleFr"='Màj plugins in-app, stockage générique, pack de connecteurs', "entries"='[{"type":"feat","titleEn":"In-app plugin update flow with permission diff","titleFr":"Màj des plugins in-app avec diff des permissions","descEn":"Plugins self-update inside Oscarr, no SSH: target version, permission diff, then a hot reload (no downtime) or a full reboot — the engine decides which.","descFr":"Les plugins se mettent à jour depuis Oscarr, sans SSH : version cible, diff des permissions, puis hot reload (sans downtime) ou reboot complet — décidé par le moteur."},{"type":"feat","titleEn":"Generic plugin storage API (KV + SQLite)","titleFr":"API de stockage générique pour plugins (KV + SQLite)","descEn":"Two isolated primitives — a key/value store and a per-plugin SQLite database — via `PluginContext.storage`, gated by the new `storage:plugin` permission. State dies with it.","descFr":"Deux primitives isolées — un key/value store et une base SQLite par plugin — via `PluginContext.storage`, gated par la permission `storage:plugin`. L''état est supprimé avec lui."},{"type":"feat","titleEn":"Indexer + download-client connector pack (5 new)","titleFr":"Pack de connecteurs indexer + download-client (×5)","descEn":"Five connectors: Prowlarr (indexer), NZBGet, SABnzbd, Transmission, Deluge (download-clients). Auth and connection testing only — actions will come via dedicated plugins.","descFr":"Cinq connecteurs : Prowlarr (indexer), NZBGet, SABnzbd, Transmission, Deluge (download-clients). Auth et test de connexion seulement — les actions viendront via des plugins dédiés."},{"type":"feat","titleEn":"Searchable service-type picker with Untested badge","titleFr":"Sélecteur de service : recherche + pastille Non testé","descEn":"The service-creation modal now opens a searchable Combobox (provider icons) instead of a native `<select>`. An amber ''Untested'' pill flags connectors not yet validated.","descFr":"Le modal de création ouvre un Combobox recherchable (icônes provider) au lieu d''un `<select>`. Une pastille « Non testé » marque les connecteurs pas encore validés."},{"type":"feat","titleEn":"Support module extracted to a standalone plugin","titleFr":"Module Support extrait en plugin autonome","descEn":"The in-core Support module now ships as the `Oscarr-Plugin-Support` plugin, removable like any other. The migration exports existing tickets so you keep your data. Core stays lean.","descFr":"Le module Support quitte le core pour le plugin `Oscarr-Plugin-Support`, désinstallable. La migration exporte les tickets existants pour ne rien perdre. Le core reste lean."},{"type":"fix","titleEn":"SonarCloud reliability sweep — 53 bugs cleared","titleFr":"Nettoyage SonarCloud — 53 bugs corrigés","descEn":"Three refactor tiers (mechanical, cosmetic, redundant-cast removal). Pure code-health, no behavioural change.","descFr":"Trois passes de refactor (mécanique, cosmétique, drop des casts redondants). Pur travail de qualité, aucun changement de comportement."},{"type":"fix","titleEn":"Log injection sanitizer hardened","titleFr":"Sanitiseur de log injection durci","descEn":"CodeQL didn''t recognise the sanitizer; rewritten as explicit per-channel branches with separate `replace()` calls. Removes the dead suppression. Closes part of #182.","descFr":"CodeQL ne reconnaissait pas le sanitiseur ; réécrit en branches explicites par canal avec des `replace()` séparés. Supprime la suppression morte. Ferme une partie de #182."},{"type":"other","titleEn":"Faster multi-arch (amd64 + arm64) release builds","titleFr":"Builds release multi-arch (amd64 + arm64) accélérés","descEn":"The release pipeline builds `linux/amd64` and `linux/arm64` images noticeably faster. The lockfile''s platform-native deps are restored, so distroless / musl installs stop failing.","descFr":"Le pipeline release sort les images `linux/amd64` et `linux/arm64` nettement plus vite. Les deps natives du lockfile sont restaurées, fini les installs cassées sur distroless/musl."}]' WHERE "version"='0.8.0';
UPDATE "Patchnote" SET "titleEn"='Account modal redesign, Jackett indexer + qBittorrent plugin', "titleFr"='Modal Compte revu, indexer Jackett + plugin qBittorrent', "entries"='[{"type":"feat","titleEn":"Discord-like account modal with plugin sections","titleFr":"Modal Compte Discord-like avec sections plugin","descEn":"Full-screen `AccountModal` replaces the avatar dropdown: a sidebar (avatar → sections → logout) and a pane. Built-ins and plugin sections merge via the new `account.section` hook.","descFr":"Un `AccountModal` plein écran remplace le dropdown avatar : sidebar (avatar → sections → logout) + panneau. Built-in et plugin fusionnent via le nouveau hook `account.section`."},{"type":"feat","titleEn":"User-selectable avatar source","titleFr":"Source d''avatar choisie par l''utilisateur","descEn":"#169 — pick which linked provider (Plex, Jellyfin, Emby, …) supplies your avatar. The new AvatarEditor shows every linked provider image and lets you swap on the fly.","descFr":"#169 — choisis quel provider connecté (Plex, Jellyfin, Emby, …) fournit ton avatar. Le nouvel AvatarEditor affiche chaque image de provider lié et te laisse swap à la volée."},{"type":"feat","titleEn":"Admin-defined custom topbar links","titleFr":"Liens topbar custom définis par l''admin","descEn":"#167 — admins publish arbitrary URL shortcuts to the home topbar (label, icon, URL, target). Pin Tautulli, Overseerr or any service in one click — no plugin needed.","descFr":"#167 — les admins publient des raccourcis URL dans la topbar (label, icône, URL, target). Épingle Tautulli, Overseerr ou n''importe quel service en un click — sans plugin."},{"type":"feat","titleEn":"Admin jump button + tooltip system","titleFr":"Bouton d''accès admin + système de tooltip","descEn":"A discreet shield button (admin-gated) now sits in every topbar for one-click jumps between the user app and admin panel. Backed by a new shared Tooltip with a fast 100ms fade.","descFr":"Un discret bouton bouclier (gated admin) dans chaque topbar pour switcher en un click entre app user et panel admin. Nouveau Tooltip partagé avec un fade rapide en 100ms."},{"type":"feat","titleEn":"Jackett indexer connector","titleFr":"Connecteur indexer Jackett","descEn":"New ''indexer'' service category, Jackett first. Its test hits the public Torznab caps endpoint (works behind an admin password); API key in query, since Jackett ignores X-Api-Key.","descFr":"Nouvelle catégorie ''indexer'', Jackett en premier. Test via le endpoint Torznab caps public (marche derrière un mot de passe admin) ; API key en query, Jackett ignorant X-Api-Key."},{"type":"feat","titleEn":"Curated icon set expanded","titleFr":"Set d''icônes curated étendu","descEn":"`DynamicIcon` (plugin nav/tabs/widgets) gains 8 new icons for subscription/achievements/stats plugins. Unknown ones log a dev warning instead of silently falling back to Puzzle.","descFr":"`DynamicIcon` (nav/tabs/widgets de plugin) gagne 8 icônes pour les plugins subscription/achievements/stats. Les inconnues warnent en dev au lieu de fallback silencieux sur Puzzle."},{"type":"fix","titleEn":"qBittorrent connection test no longer 403s","titleFr":"Le test de connexion qBittorrent ne renvoie plus 403","descEn":"Used to hit `/api/v2/app/version` unauthenticated (misleading 403). Now runs the full `/auth/login` flow and returns AUTH_FAILED, AUTH_BANNED or AUTH_NO_SESSION.","descFr":"Le provider tapait `/api/v2/app/version` sans s''authentifier (403 trompeur). Il fait le flux `/auth/login` complet et renvoie AUTH_FAILED, AUTH_BANNED ou AUTH_NO_SESSION."},{"type":"fix","titleEn":"Admin-only plugins no longer reachable by URL","titleFr":"Les plugins admin-only ne sont plus accessibles par URL","descEn":"Any plugin with a `frontend` field was mountable at `/p/<id>` without a `nav` contribution, so admin-only plugins were URL-reachable. `/p/<id>` now requires a `nav` contribution.","descFr":"Tout plugin avec un champ `frontend` était montable à `/p/<id>` sans contribution `nav` — les plugins admin-only étaient donc accessibles par URL. `/p/<id>` exige désormais `nav`."}]' WHERE "version"='0.7.8';
UPDATE "Patchnote" SET "titleEn"='Customisable dashboard, install metrics & live nav refresh', "titleFr"='Dashboard perso, métriques d''install plugin & nav live', "entries"='[{"type":"feat","titleEn":"Customisable dashboard tabs and widgets","titleFr":"Onglets et widgets de dashboard personnalisables","descEn":"Each dashboard tab gets an optional icon (curated 56-icon set). Edit mode: a Pencil button per widget sets a title, icon, or ''show header'' toggle. Overrides survive drag/resize.","descFr":"Chaque onglet peut recevoir une icône (set curated de 56). En édition, un crayon par widget règle titre, icône ou ''afficher le header''. Overrides préservés au drag/resize."},{"type":"feat","titleEn":"Live install count on the Discover tab","titleFr":"Nombre d''installs en direct sur Discover","descEn":"Discover cards now show total GitHub release-asset downloads next to the star count — a free signal. Plugins shipping a tarball/HEAD archive show 0 (GitHub doesn''t track those).","descFr":"Les cartes Discover affichent le total de downloads d''assets Release — signal gratuit. Les plugins shippant une archive tarball/HEAD affichent 0 (non tracké par GitHub)."},{"type":"feat","titleEn":"Verbose request log toggle","titleFr":"Toggle de log de requêtes verbeux","descEn":"Opt-in toggle in Admin → Système → Instance → Debug that logs every /api/* response (method, path, status…) to AppLog. Off by default — disable when done, it writes to the DB.","descFr":"Toggle dans Admin → Système → Instance → Debug qui logge chaque réponse /api/* (méthode, path, status…) dans AppLog. Off par défaut — désactive dès que t''as fini, ça écrit en DB."},{"type":"feat","titleEn":"Plugin tab URL sync","titleFr":"Sync URL des sous-onglets Plugins","descEn":"Admin → Plugins → Installed / Discover sub-tab now syncs to the URL via ?sub=. Refresh, bookmark or share and you land on the right tab.","descFr":"Le sous-onglet Installed / Discover dans Admin → Plugins se synchronise à l''URL via ?sub=. Refresh, bookmark ou partage un lien et tu atterris au bon endroit."},{"type":"fix","titleEn":"Live nav refresh on plugin toggle","titleFr":"Refresh nav live au toggle plugin","descEn":"Toggling a plugin used to leave nav entries and widgets stuck until F5. usePluginUI now refetches every mounted hook in place; the pill shows an ''Enabling…''/''Disabling…'' spinner.","descFr":"Activer/désactiver un plugin laissait ses entrées de nav et widgets figés jusqu''à F5. usePluginUI refetch chaque hook monté ; le pill affiche un spinner ''Enabling…''/''Disabling…''."},{"type":"fix","titleEn":"Stale ''update available'' badge","titleFr":"Badge ''update available'' obsolète","descEn":"The badge could lag ~1h — it compared `latest !== installed`, not semver. Now `latest > installed`, and cache invalidates on install/uninstall so it clears at once.","descFr":"Le badge pouvait traîner ~1h — il comparait `latest !== installed`, pas un semver. Maintenant `latest > installed`, et cache s''invalide à l''install/uninstall — nettoyage immédiat."},{"type":"fix","titleEn":"Update resolver follows /releases when /latest 404s","titleFr":"Le résolveur d''update suit /releases si /latest 404","descEn":"GitHub 404s /releases/latest when no release is flagged latest. The resolver now falls back to /releases?per_page=30 sorted by semver desc, so install and update keep working.","descFr":"GitHub renvoie 404 sur /releases/latest quand aucune release n''est marquée latest. Le résolveur fallback sur /releases?per_page=30 trié par semver desc, pour install et update."},{"type":"fix","titleEn":"Bust stale browser caches on version flip","titleFr":"Purge des caches navigateur au changement de version","descEn":"Stale /api/* HTML could load the SPA shell on backend routes and blank pages. Now index.html sends no-store and version mismatch triggers Clear-Site-Data. Sessions and JWT survive.","descFr":"Du HTML /api/* obsolète chargeait le shell SPA sur le backend (pages blanches). index.html envoie no-store et un mismatch déclenche Clear-Site-Data. Sessions et JWT survivent."},{"type":"fix","titleEn":"Logs ''Copy'' button works on LAN dev","titleFr":"Bouton ''Copier'' des logs marche en dev LAN","descEn":"navigator.clipboard needs a secure context, so on a LAN IP the button failed silently. New helper falls back to document.execCommand(''copy''), so copy works over plain HTTP.","descFr":"navigator.clipboard exige un secure context ; sur IP LAN le bouton était muet. Nouveau helper avec fallback sur document.execCommand(''copy'') : la copie marche en HTTP plain."}]' WHERE "version"='0.7.7';
UPDATE "Patchnote" SET "titleEn"='Composable admin dashboard + plugin install fix', "titleFr"='Dashboard admin composable + correctif install plugin', "entries"='[{"type":"feat","titleEn":"Composable admin dashboard","titleFr":"Dashboard admin composable","descEn":"A drag-and-drop grid replaces the static admin DashboardTab. Three widgets ship (stats, health, version + plugin updates); plugins add their own via admin.dashboard.widget hook.","descFr":"Une grille drag-and-drop remplace le DashboardTab statique. Trois widgets (stats, santé, version + updates plugins) ; les plugins ajoutent les leurs via admin.dashboard.widget."},{"type":"feat","titleEn":"WYSIWYG widget edit mode","titleFr":"Mode édition WYSIWYG","descEn":"Editing no longer wraps each widget in an extra card. The drag handle and remove button float in the corners with a dashed outline — what you see in edit is what you get in view.","descFr":"En édition, plus de card supplémentaire autour des widgets. Poignée de drag et bouton supprimer flottent dans les coins avec un liseré tireté ; l''édition = le rendu final."},{"type":"fix","titleEn":"Plugin install across filesystems","titleFr":"Install plugin cross-filesystem","descEn":"In Docker where /tmp is tmpfs and /app the persistent volume, install failed with EXDEV (cross-device link). Tarballs now stage in the plugins dir so the final rename stays atomic.","descFr":"En Docker où /tmp est tmpfs et /app le volume persistant, l''install échouait avec EXDEV (cross-device link). Les tarballs se stagent dans le dossier plugins pour rester atomique."}]' WHERE "version"='0.7.3';
UPDATE "Patchnote" SET "titleEn"='Multi-tab dashboard + plugin install via release assets', "titleFr"='Dashboard multi-onglets + install plugin via assets release', "entries"='[{"type":"feat","titleEn":"Multi-tab admin dashboard","titleFr":"Dashboard admin multi-onglets","descEn":"Add named tabs with +, double-click to rename, remove the active one in edit mode. Last tab stays locked so you''re never empty; widgets live per-tab but stay unique across the layout.","descFr":"Onglets nommés : ajoute via +, double-clique pour renommer, supprime l''actif en mode édition. Le dernier reste verrouillé (jamais vide) ; widgets uniques sur tout le layout."},{"type":"ui","titleEn":"Reset confirm modal","titleFr":"Modal de confirmation Reset","descEn":"Reset-to-default left the toolbar for a proper a11y modal (Escape, focus-trap, focus-return), shown only in edit mode.","descFr":"Réinitialiser quitte la toolbar pour une vraie modal accessible (Escape, piège de focus, retour), visible en mode édition seulement."},{"type":"fix","titleEn":"Plugin install respects release assets","titleFr":"L''install plugin respecte les assets de release","descEn":"Install hardcoded tarball/HEAD, which drops gitignored builds — plugins shipping dist/ as a Release asset failed. Now the first .tar.gz release asset wins, fallback to tarball/HEAD.","descFr":"L''install hardcodait tarball/HEAD, qui exclut les builds gitignorés — les plugins livrant dist/ en asset Release plantaient. Le premier asset .tar.gz gagne, fallback tarball/HEAD."},{"type":"docs","titleEn":"Plugin release workflow template","titleFr":"Template de workflow de release plugin","descEn":"docs/plugins.md gains a ''Releasing a plugin'' section with a copy-paste GitHub Actions workflow that builds, packs and uploads a tarball asset on every v* tag.","descFr":"docs/plugins.md gagne une section ''Releasing a plugin'' avec un workflow GitHub Actions copy-paste qui build, packe et upload un asset tarball à chaque tag v*."}]' WHERE "version"='0.7.4';
UPDATE "Patchnote" SET "titleEn"='Plugin install hotfix (CSP + bind-mount perms)', "titleFr"='Hotfix install plugin (CSP + permissions bind-mount)', "entries"='[{"type":"fix","titleEn":"Resolve plugin install URL server-side","titleFr":"Résolution de l''URL d''install plugin côté serveur","descEn":"0.7.4''s frontend fetch to api.github.com was blocked by the prod CSP. It now resolves on the backend (already trusted for GitHub), so the fix works in prod.","descFr":"Le fetch frontend de 0.7.4 vers api.github.com était bloqué par le CSP de prod. La résolution passe côté backend (déjà autorisé pour GitHub), pour que le fix marche en prod."},{"type":"fix","titleEn":"Auto-chown the plugins directory at boot","titleFr":"chown automatique du dossier plugins au boot","descEn":"Host bind-mounts of /app/packages/plugins hit EACCES on install (dir not owned by uid 1001). The entrypoint now chowns + chmods 2775 setgid at boot, like /data.","descFr":"Un bind-mount host de /app/packages/plugins tombait sur EACCES à l''install (dossier pas owné par l''uid 1001). L''entrypoint chown + chmod 2775 setgid au boot, comme pour /data."}]' WHERE "version"='0.7.5';
UPDATE "Patchnote" SET "titleEn"='Arch-aware plugin install + native-deps release guide', "titleFr"='Install plugin par architecture + guide deps natives', "entries"='[{"type":"feat","titleEn":"Arch-aware plugin install resolver","titleFr":"Résolveur d''install plugin par architecture","descEn":"Native-module plugins (better-sqlite3, sharp, …) can''t ship one universal asset — .node binaries are arch-specific. The resolver picks an arch-matching asset, else a universal one, else the source tarball.","descFr":"Les plugins à modules natifs (better-sqlite3, sharp, …) ne tiennent pas dans un asset universel : binaires .node liés à l''archi. Le résolveur pioche un asset matchant l''archi, sinon universel, sinon le tarball."},{"type":"docs","titleEn":"Native-deps guide for plugin authors","titleFr":"Guide deps natives pour plugin authors","descEn":"docs/plugins.md ''Releasing a plugin'' now covers the resolution order, asset requirements, universal vs per-arch choices, common native-dep offenders, and a per-arch matrix workflow.","descFr":"docs/plugins.md ''Releasing a plugin'' couvre l''ordre de résolution, les exigences d''asset, le choix universel vs per-arch, les deps natives connues et un workflow matrice per-arch."}]' WHERE "version"='0.7.6';
UPDATE "Patchnote" SET "titleEn"='Security hardening, a11y pass & plugin CSS isolation', "titleFr"='Durcissement sécurité, a11y & isolation CSS plugins', "entries"='[{"type":"feat","titleEn":"Security headers (Helmet)","titleFr":"En-têtes de sécurité (Helmet)","descEn":"Strict CSP, X-Frame-Options DENY, Referrer-Policy, X-Content-Type-Options, HSTS behind HTTPS. Closes the common XSS/clickjacking blast radius.","descFr":"CSP strict, X-Frame-Options DENY, Referrer-Policy, X-Content-Type-Options, HSTS derrière HTTPS. Ferme la plupart des vecteurs XSS/clickjacking."},{"type":"feat","titleEn":"Signed backups + re-auth on restore","titleFr":"Sauvegardes signées + re-auth à la restauration","descEn":"Backups are HMAC-signed at creation; a tampered archive fails verification on restore. Admin re-enters their password to apply one.","descFr":"Les sauvegardes sont signées HMAC à la création ; une archive modifiée est refusée à la restauration. L''admin re-saisit son mot de passe pour l''appliquer."},{"type":"feat","titleEn":"Service secrets masking","titleFr":"Masquage des secrets services","descEn":"GET /admin/services no longer returns plaintext API keys/tokens. A reveal endpoint exposes the value on explicit admin action, logged for audit.","descFr":"GET /admin/services ne renvoie plus les clés/tokens en clair. Un endpoint de reveal expose la valeur à la demande, tracé dans les logs."},{"type":"feat","titleEn":"CSRF + SSRF guards","titleFr":"Guards CSRF + SSRF","descEn":"Admin mutations require X-Requested-With: oscarr. Service URLs are checked against private-IP ranges — permissive by default for LAN, opt-in strict mode.","descFr":"Les mutations admin exigent X-Requested-With: oscarr. Les URLs service sont validées contre les IP privées — permissif par défaut en LAN, mode strict opt-in."},{"type":"feat","titleEn":"Rate-limiting on mutations","titleFr":"Limitation de débit sur les mutations","descEn":"POST /requests, /requests/collection, /admin/sync/force, /admin/restart, Plex PIN, Discord OAuth — all capped against spam and DoS.","descFr":"POST /requests, /requests/collection, /admin/sync/force, /admin/restart, Plex PIN, Discord OAuth — tous limités contre spam et DoS."},{"type":"feat","titleEn":"Plugin CSS isolation","titleFr":"Isolation CSS des plugins","descEn":"Plugin stylesheets are scoped to the plugin''s DOM subtree — installing one no longer leaks Tailwind utilities into the app.","descFr":"Les styles des plugins sont scopés à leur sous-arbre DOM — installer un plugin ne propage plus ses utilitaires Tailwind au reste de l''app."},{"type":"feat","titleEn":"Update banner in sidebar","titleFr":"Bannière de mise à jour dans la sidebar","descEn":"When a new Oscarr release lands on GitHub, the admin sidebar links straight to the release notes.","descFr":"Quand une nouvelle version Oscarr sort sur GitHub, la sidebar admin affiche un lien direct vers les release notes."},{"type":"feat","titleEn":"Accessibility pass","titleFr":"Passe d''accessibilité","descEn":"Focus-visible rings everywhere, aria-labels on icon buttons, a useModal hook (Escape + focus-trap + focus-return) app-wide, skip-to-content link, SR-announced toasts.","descFr":"Focus visible partout, aria-label sur les boutons icon-only, hook useModal (Escape + piège de focus + retour) partout, lien saut au contenu, toasts annoncés aux lecteurs d''écran."},{"type":"perf","titleEn":"Admin bundle code-splitting","titleFr":"Code-splitting du bundle admin","descEn":"Non-admins no longer download the admin UI upfront. Services editor, query builder, plugin manager load on demand — initial bundle cut 2-3x.","descFr":"Les non-admins ne téléchargent plus l''UI admin au démarrage. Éditeur de services, query builder, gestionnaire de plugins à la demande — bundle initial divisé par 2-3×."},{"type":"perf","titleEn":"Frontend & data wins","titleFr":"Gains frontend & données","descEn":"Memoized AuthContext, stable RequestCard handlers, NSFW filter via SQLite json_each + cache, ~40% smaller /requests payloads, polling paused on hidden tabs, new Prisma indexes.","descFr":"AuthContext mémoïsé, handlers de cards stables, filtre NSFW via SQLite json_each + cache, /requests ~40% plus léger, polling en pause si onglet caché, nouveaux indexes Prisma."},{"type":"refactor","titleEn":"Backend architecture cleanup","titleFr":"Nettoyage architecture backend","descEn":"Backup + push extracted to services/, breaking the service→route cycle. TMDB route down to 17 lines via a shared fetchList. Requests split into create/lifecycle/list/maintenance.","descFr":"Backup + push extraits dans services/, cycle service→route cassé. Route TMDB à 17 lignes via un helper fetchList. Requests splitté en create/lifecycle/list/maintenance."},{"type":"refactor","titleEn":"Admin tabs modularized + per-plugin Tailwind","titleFr":"Tabs admin modularisés + Tailwind par plugin","descEn":"PluginsTab and ServicesTab split into hook + presentational components (<200 LoC each). Plugins compile their own Tailwind via a shared preset — no more purged utilities.","descFr":"PluginsTab et ServicesTab découpés en hook + composants présentationnels (<200 lignes). Les plugins compilent leur Tailwind via un preset partagé — plus d''utilities purgées."},{"type":"feat","titleEn":"Nightly release channel","titleFr":"Canal de release nightly","descEn":"The release workflow gains a nightly dispatch — push :nightly images to test in your prod without touching :latest. Pre-release tags (v1.0.0-rc.1) no longer alias :latest.","descFr":"Le workflow de release gagne un mode nightly — push d''images :nightly pour tester en prod perso sans impacter :latest. Les tags pre-release (v1.0.0-rc.1) n''aliasent plus :latest."},{"type":"fix","titleEn":"Dependency patches","titleFr":"Patches de dépendances","descEn":"serialize-javascript RCE and follow-redirects header leak patched via npm overrides. Zero high/moderate vulnerabilities from npm audit.","descFr":"RCE serialize-javascript et fuite de header follow-redirects patchés via npm overrides. Zéro vulnérabilité high/moderate rapportée par npm audit."},{"type":"fix","titleEn":"Stability fixes","titleFr":"Correctifs de stabilité","descEn":"Fixed Rules-of-Hooks violations in RolesTab/KeywordsTab TagCell and the backup path after the service extraction. Service tests now separate SSRF blocks from real connectivity failures.","descFr":"Violations Rules-of-Hooks (RolesTab/KeywordsTab) et chemin backup corrigés après l''extraction du service. Les tests service distinguent blocages SSRF et vrais échecs de connexion."}]' WHERE "version"='0.7.0';
UPDATE "Patchnote" SET "titleEn"='Plugin ecosystem, homepage builder & PWA', "titleFr"='Écosystème de plugins, accueil personnalisable & PWA', "entries"='[{"type":"feat","titleEn":"Plugin system v2","titleFr":"Système de plugins v2","descEn":"Rewritten engine: versioned context factory, event bus, lifecycle hooks, settings validation, plugin logs and error boundaries.","descFr":"Moteur réécrit : contexte versionné, bus d''événements, hooks de lifecycle, validation des settings, logs et error boundaries."},{"type":"feat","titleEn":"Plugin marketplace","titleFr":"Marketplace de plugins","descEn":"Browse community plugins from the admin panel, filter by category, spot updates, one-click server reload.","descFr":"Parcours les plugins communautaires depuis l''admin, filtre par catégorie, repère les mises à jour, recharge le serveur en un clic."},{"type":"feat","titleEn":"Plugin SDK","titleFr":"SDK pour plugins","descEn":"`@oscarr/sdk` — lightweight helpers for plugin developers: API client, formatters, namespaced storage.","descFr":"`@oscarr/sdk` — helpers légers pour les devs de plugins : client API, formateurs, stockage namespacé."},{"type":"feat","titleEn":"Customizable homepage","titleFr":"Page d''accueil personnalisable","descEn":"Reorder, hide or add homepage sections with a TMDB query builder, endpoint presets (Now Playing, Top Rated...) and live preview.","descFr":"Réordonne, masque ou ajoute des sections d''accueil : constructeur de requêtes TMDB, presets d''endpoints (Au cinéma, Mieux notés...) et aperçu en direct."},{"type":"feat","titleEn":"PWA support","titleFr":"Support PWA","descEn":"Oscarr installs as a Progressive Web App with offline caching for TMDB images and automatic service worker updates.","descFr":"Oscarr s''installe comme app web progressive : cache hors ligne des images TMDB et service worker mis à jour automatiquement."},{"type":"feat","titleEn":"Push notifications","titleFr":"Notifications push","descEn":"Get notified on your phone when your requested media is available — enable from the user menu, works on Android and desktop.","descFr":"Sois notifié sur ton téléphone quand ton média demandé est dispo — active depuis le menu utilisateur, marche sur Android et desktop."},{"type":"feat","titleEn":"Request filters","titleFr":"Filtres de demandes","descEn":"Filter by status, media type, user and date range.","descFr":"Filtre par statut, type de média, utilisateur et plage de dates."},{"type":"feat","titleEn":"Granular frontend RBAC","titleFr":"RBAC frontend granulaire","descEn":"Custom roles (Moderator, Support Manager) now work in the UI — approvals, tickets and admin access driven by specific permissions.","descFr":"Les rôles personnalisés (Modérateur, Support Manager) marchent dans l''UI : approbation, tickets et accès admin selon les permissions."},{"type":"perf","titleEn":"Centralized API hooks","titleFr":"Hooks API centralisés","descEn":"Shared hooks for TMDB fetching, paginated discovery with infinite scroll and calendar — no more duplicated logic across pages.","descFr":"Hooks partagés pour le fetch TMDB, la découverte paginée (scroll infini) et le calendrier — fini la logique dupliquée."},{"type":"refactor","titleEn":"Detail page action button redesign","titleFr":"Refonte du bouton d''action page détail","descEn":"Swapped a 90-line nested ternary for an explicit state machine — 11 documented states, pure function, fully testable.","descFr":"Chaîne ternaire de 90 lignes remplacée par une state machine explicite : 11 états documentés, fonction pure, testable."},{"type":"fix","titleEn":"Upcoming status accuracy","titleFr":"Précision du statut Prochainement","descEn":"Movies already in theaters no longer show as Upcoming — uses the earliest known release date.","descFr":"Les films déjà au cinéma ne s''affichent plus comme Prochainement — utilise la date de sortie la plus ancienne connue."},{"type":"fix","titleEn":"Plugin security hardening","titleFr":"Durcissement sécurité plugins","descEn":"Path traversal protection, SSRF prevention, RBAC enforcement, extension whitelist on frontend serving.","descFr":"Protection path traversal, prévention SSRF, application RBAC, whitelist d''extensions sur le serving frontend."}]' WHERE "version"='0.6.0';
UPDATE "Patchnote" SET "titleEn"='Jellyfin, Emby, Calendar & Discover filters', "titleFr"='Jellyfin, Emby, calendrier et filtres de découverte', "entries"='[{"type":"feat","titleEn":"Jellyfin & Emby authentication","titleFr":"Authentification Jellyfin & Emby","descEn":"Sign in with your Jellyfin or Emby credentials, import users, link accounts.","descFr":"Connecte-toi avec tes identifiants Jellyfin ou Emby, importe les utilisateurs, lie les comptes."},{"type":"feat","titleEn":"Calendar redesign","titleFr":"Refonte du calendrier","descEn":"Grid view with 6-day columns and compact cards, list view with poster scroll, toggle persisted.","descFr":"Vue grille (colonnes de 6 jours, cartes compactes), vue liste avec défilement de posters, choix persisté."},{"type":"feat","titleEn":"Discover & category filters","titleFr":"Filtres de découverte et catégories","descEn":"Sort by popularity/rating/date, release year, minimum rating, hide already requested media.","descFr":"Tri par popularité/note/date, année de sortie, note minimum, masquage des médias déjà demandés."},{"type":"feat","titleEn":"Cast section redesign","titleFr":"Refonte du casting","descEn":"Poster-style cards with scroll arrows, clickable links to the person filmography page.","descFr":"Cartes style poster avec flèches de défilement, liens cliquables vers la filmographie."},{"type":"feat","titleEn":"Person page","titleFr":"Page personne","descEn":"Biography, metadata and filmography grid with availability badges.","descFr":"Biographie, métadonnées et grille de filmographie avec badges de disponibilité."},{"type":"feat","titleEn":"Changelog modal","titleFr":"Modal des nouveautés","descEn":"In-app release notes with automatic notification on update.","descFr":"Notes de version intégrées, avec notification automatique après mise à jour."},{"type":"feat","titleEn":"Quality options per role","titleFr":"Options de qualité par rôle","descEn":"Restrict quality options to specific roles, override auto-approval per quality.","descFr":"Restreins les options de qualité à des rôles précis, override de l''auto-approbation par qualité."},{"type":"fix","titleEn":"Login page redesigned","titleFr":"Page de connexion repensée","descEn":"Provider selection first, clean credential forms, brand colors.","descFr":"Sélection du fournisseur d''abord, formulaires propres, couleurs de marque."},{"type":"fix","titleEn":"Keyword tag dropdown clipped","titleFr":"Menu déroulant des mots-clés coupé","descEn":"Portaled dropdown in Admin → Media → Keywords.","descFr":"Menu déroulant portalé dans Admin → Médias → Mots-clés."},{"type":"fix","titleEn":"Cookie auth on HTTP deployments","titleFr":"Auth cookie sur les déploiements HTTP","descEn":"Fixed secure cookie flag for Docker setups without reverse proxy, added `trustProxy` for correct HTTPS detection.","descFr":"Flag secure cookie corrigé pour les setups Docker sans reverse proxy, `trustProxy` ajouté pour la détection HTTPS."},{"type":"fix","titleEn":"All logs and errors in English","titleFr":"Tous les logs et erreurs en anglais","descEn":"Replaced 165 hardcoded French strings, added debug logging for support.","descFr":"165 chaînes françaises codées en dur remplacées, logging debug ajouté pour le support."},{"type":"feat","titleEn":"Backup & restore system","titleFr":"Système de sauvegarde et restauration","descEn":"Download/restore backups from the admin panel, auto-backup every 6h with retention, optional TMDB cache exclusion.","descFr":"Télécharge/restaure des sauvegardes depuis l''admin, sauvegarde auto toutes les 6h avec rétention, exclusion optionnelle du cache TMDB."}]' WHERE "version"='0.5.0';
UPDATE "Patchnote" SET "titleEn"='Bug fixes & performance', "titleFr"='Corrections et performances', "entries"='[{"type":"fix","titleEn":"Episode badge showing undefined","titleFr":"Badge épisode affichant undefined","descEn":"Fixed SundefinedEundefined on recently added cards from raw Sonarr episode data","descFr":"Fini le SundefinedEundefined sur les cartes récemment ajoutées, dû aux données brutes de Sonarr"},{"type":"perf","titleEn":"Homepage loads instantly","titleFr":"La page d''accueil charge instantanément","descEn":"One DB query replaces 100+ TMDB API calls for NSFW detection","descFr":"Une seule requête DB remplace 100+ appels API TMDB pour la détection NSFW"},{"type":"fix","titleEn":"False unsaved changes on admin page","titleFr":"Faux indicateur de modifications non sauvegardées","descEn":"Race condition between concurrent calls on the settings page","descFr":"Condition de course entre appels API concurrents sur la page paramètres"}]' WHERE "version"='0.4.2';
UPDATE "Patchnote" SET "titleEn"='Webhooks, requests redesign & community features', "titleFr"='Webhooks, refonte des demandes et communauté', "entries"='[{"type":"feat","titleEn":"Radarr/Sonarr webhooks","titleFr":"Webhooks Radarr/Sonarr","descEn":"Instant availability updates, no waiting for sync","descFr":"Disponibilité mise à jour instantanément, sans attendre le sync"},{"type":"feat","titleEn":"Requests page redesign","titleFr":"Refonte de la page demandes","descEn":"New card layout, filter tabs, bulk cleanup, quality selection","descFr":"Nouveau design en cartes, filtres, nettoyage en masse, choix de qualité"},{"type":"feat","titleEn":"Blacklist system","titleFr":"Système de liste noire","descEn":"Block specific media from being requested","descFr":"Empêche certains médias d''être demandés"},{"type":"feat","titleEn":"NSFW blur with admin toggle","titleFr":"Flou NSFW avec toggle admin","descEn":"Auto-detects and blurs mature content","descFr":"Détecte et floute automatiquement le contenu mature"},{"type":"fix","titleEn":"TV requests failing without tvdbId","titleFr":"Demandes TV échouant sans tvdbId","descEn":"Now resolves tvdbId from TMDB automatically","descFr":"Résolution automatique du tvdbId depuis TMDB"}]' WHERE "version"='0.4.0';
UPDATE "Patchnote" SET "titleEn"='Security & stability', "titleFr"='Sécurité et stabilité', "entries"='[{"type":"fix","titleEn":"Security dependencies updated","titleFr":"Dépendances de sécurité mises à jour"},{"type":"fix","titleEn":"Sync crashes on large libraries","titleFr":"Crash du sync sur les grosses bibliothèques","descEn":"Fixed SQLite parameter-limit overflow on large Radarr/Sonarr libraries","descFr":"Corrigé le dépassement de limite de paramètres SQLite sur les grosses bibliothèques"}]' WHERE "version"='0.3.1';

INSERT INTO "Patchnote" ("version", "type", "date", "titleEn", "titleFr", "entries") VALUES
('0.8.5', 'patch', '2026-07-11T10:00:00.000Z', 'More reliable media states + big backend cleanup', 'Statuts média fiabilisés + gros nettoyage backend', '[{"type":"feat","titleEn":"Unified media states across the app","titleFr":"Statuts média unifiés dans toute l''app","descEn":"A movie/show''s availability and status now come from one canonical source — fewer wrong \"Requested\"/\"Available\" badges.","descFr":"Disponibilité et statut des films/séries viennent désormais d''une source unique et cohérente — moins de badges « Demandé »/« Disponible » erronés."},{"type":"fix","titleEn":"Downloaded shows shown as requestable","titleFr":"Séries dispo affichées comme demandables","descEn":"A Sonarr-synced show could lose its Sonarr link and seasons — and reappear as requestable — when its TMDB id resolved. Fixed.","descFr":"Une série synchronisée depuis Sonarr pouvait perdre son lien Sonarr et ses saisons — et réapparaître comme « à demander » — quand son id TMDB se résolvait. Corrigé."},{"type":"fix","titleEn":"Request button stuck after a decline","titleFr":"Bouton « Demander » bloqué après un refus","descEn":"An admin-declined request kept the \"Requested\" badge and hid the button; it now reappears right away.","descFr":"Une requête refusée par un admin gardait le badge « Demandé » et masquait le bouton ; il réapparaît maintenant tout de suite."},{"type":"fix","titleEn":"Discover filters: frozen grid / mixed results","titleFr":"Filtres Discover : grille figée / résultats mélangés","descEn":"Changing a filter mid-scroll could freeze the grid or stack two filters'' results. Fixed.","descFr":"Changer de filtre en cours de scroll pouvait figer la grille ou empiler les résultats de deux filtres. Corrigé."},{"type":"fix","titleEn":"Correct statuses on Radarr/Sonarr grab","titleFr":"Statuts corrigés au grab Radarr/Sonarr","descEn":"When an *arr grabs a download, linked requests correctly flip to \"processing\" (atomic update).","descFr":"Quand un *arr récupère un téléchargement, les requêtes liées passent bien en « en cours » (mise à jour atomique)."},{"type":"fix","titleEn":"Overseerr compat: count and filter agree","titleFr":"Compat Overseerr : count et filtre cohérents","descEn":"`/media/count` and `/media?filter=pending` disagreed on searching media. Aligned for Maintainerr & co.","descFr":"`/media/count` et `/media?filter=pending` comptaient différemment les médias en recherche. Aligné pour Maintainerr & co."},{"type":"fix","titleEn":"Saving settings no longer returns the API key","titleFr":"La sauvegarde des réglages ne renvoie plus la clé API","descEn":"The settings PUT response leaked the instance API key (GET already masked it). Fixed.","descFr":"La réponse du PUT réglages exposait la clé API de l''instance (le GET la masquait déjà). Corrigé."},{"type":"perf","titleEn":"Big internal backend cleanup","titleFr":"Gros nettoyage interne du backend","descEn":"~13 dedup workstreams folding duplicated logic into shared helpers (settings, *arr clients, RBAC, TV placeholders…). Lighter and more consistent.","descFr":"~13 chantiers de dédup : logique dupliquée regroupée en helpers partagés (réglages, clients *arr, RBAC, placeholders TV…). Plus léger et cohérent."}]')
ON CONFLICT ("version") DO NOTHING;
